const opportunities = [
  { id: 'OPP-001', title: 'Native mobile app (iOS + Android)', reach: 8, impact: 7, confidence: 6, effort: 9, strategic_fit: 8, category: 'new-capability', tags: ['mobile', 'retention'] },
  { id: 'OPP-002', title: 'Bulk CSV import for onboarding', reach: 6, impact: 8, confidence: 9, effort: 3, strategic_fit: 7, category: 'friction-removal', tags: ['onboarding', 'activation'] },
  { id: 'OPP-003', title: 'AI-powered project risk detection', reach: 5, impact: 9, confidence: 5, effort: 8, strategic_fit: 9, category: 'ai-feature', tags: ['ai', 'enterprise'] },
  { id: 'OPP-004', title: 'SSO (SAML 2.0) for enterprise', reach: 4, impact: 10, confidence: 9, effort: 5, strategic_fit: 10, category: 'enterprise-requirement', tags: ['enterprise', 'security'] },
  { id: 'OPP-005', title: 'Slack integration (two-way sync)', reach: 7, impact: 6, confidence: 8, effort: 4, strategic_fit: 6, category: 'integration', tags: ['integrations', 'collaboration'] },
  { id: 'OPP-006', title: 'Custom fields on projects and tasks', reach: 9, impact: 7, confidence: 8, effort: 5, strategic_fit: 7, category: 'customisation', tags: ['flexibility', 'enterprise'] },
  { id: 'OPP-007', title: 'Advanced permissions (role-based access)', reach: 5, impact: 8, confidence: 7, effort: 6, strategic_fit: 8, category: 'enterprise-requirement', tags: ['enterprise', 'security'] },
  { id: 'OPP-008', title: 'Executive dashboard view', reach: 4, impact: 7, confidence: 7, effort: 4, strategic_fit: 7, category: 'reporting', tags: ['reporting', 'enterprise'] },
  { id: 'OPP-009', title: 'Time tracking built-in', reach: 5, impact: 5, confidence: 6, effort: 6, strategic_fit: 4, category: 'new-capability', tags: ['time-tracking'] },
  { id: 'OPP-010', title: 'Dark mode UI', reach: 7, impact: 3, confidence: 9, effort: 2, strategic_fit: 3, category: 'ui-polish', tags: ['ui', 'delight'] }
];
return opportunities.map(o => ({ json: o }));

const all = $input.all().map(i => i.json);
const valid = all.filter(o => o.id && o.title && o.reach != null && o.impact != null && o.confidence != null && o.effort != null);
const skipped = all.length - valid.length;
// Compute RICE score for each
const scored = valid.map(o => {
  const rice = o.effort > 0 ? Math.round(((o.reach * o.impact * (o.confidence/10)) / o.effort) * 10) / 10 : 0;
  const strategic_bonus = ((o.strategic_fit || 5) - 5) * 0.1; // small modifier
  const adjusted = Math.round((rice + strategic_bonus) * 10) / 10;
  return { ...o, rice_score: rice, adjusted_score: adjusted };
});
// Sort by adjusted score descending
scored.sort((a, b) => b.adjusted_score - a.adjusted_score);
// Add rank
scored.forEach((o, i) => { o.rank = i + 1; });
const lines = scored.map(o =>
  `#${o.rank} [RICE: ${o.rice_score}] ${o.id}: ${o.title}\n   Category: ${o.category} | Tags: ${(o.tags||[]).join(', ')}\n   R:${o.reach} I:${o.impact} C:${o.confidence} E:${o.effort} Fit:${o.strategic_fit||'N/A'}`
).join('\n');
const report = [
  `OPPORTUNITY SCORING REPORT`,
  `Run: ${new Date().toISOString()} | Opportunities: ${valid.length} (${skipped} skipped)`,
  `Method: RICE (Reach × Impact × Confidence% / Effort) + strategic fit modifier`,
  `All scores on 0–10 scale per dimension.`,
  ``,
  `RANKED OPPORTUNITIES:`,
  lines
].join('\n');
return [{ json: { scored, report_text: report, skipped, total: valid.length } }];
